# Cross-module shape inheritance and interface demonstration

interface IDrawable:
    def draw(self) -> str: ...

@abstract
class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @virtual
    def area(self) -> float:
        return 0.0

    @virtual
    def describe(self) -> str:
        return f"Shape: {self.name}"

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, name: str, width: float, height: float):
        super().__init__(name)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def describe(self) -> str:
        return f"Rectangle {self.name} ({self.width} x {self.height})"

class Circle(Shape):
    radius: float
    @static PI: float = 3.14159

    def __init__(self, name: str, radius: float):
        super().__init__(name)
        self.radius = radius

    @override
    def area(self) -> float:
        return Circle.PI * self.radius * self.radius

    @override
    def describe(self) -> str:
        return f"Circle {self.name} (r={self.radius})"

class DrawablePoint(Shape, IDrawable):
    x: float
    y: float

    def __init__(self, name: str, x: float, y: float):
        super().__init__(name)
        self.x = x
        self.y = y

    @override
    def draw(self) -> str:
        return f"Point at ({self.x}, {self.y})"

    @override
    def describe(self) -> str:
        return f"Point {self.name} ({self.x}, {self.y})"

