# Utility functions working with cross-module shapes

from shapes import Shape, IDrawable, Rectangle

def calculate_total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for s in shapes:
        total += s.area()
    return total

def create_default_rectangle() -> Rectangle:
    return Rectangle("default", 5.0, 3.0)

def describe_all(shapes: list[Shape]) -> list[str]:
    descriptions: list[str] = []
    for s in shapes:
        descriptions.append(s.describe())
    return descriptions
